utton -->\r\n        <a href=\"https://bisurejobs.22web.org/feed_landing_all.php\" \r\n           class=\"floating-btn\" \r\n           target=\"_blank\">\r\n            📋 View All Jobs\r\n        </a>\r\n    </body>\r\n    </html>', 'Sent', NULL, '2026-05-23 18:04:56', '2026-05-23 15:04:56'),
