(38, 1, 'Latest Job Opportunities - BISure Jobs', '\r\n    <!DOCTYPE html>\r\n    <html>\r\n    <head>\r\n        <meta charset=\"UTF-8\">\r\n        <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n        <title>Latest Job Opportunities</title>\r\n        <style>\r\n            /* Global Styles */\r\n            body {\r\n                margin: 0;\r\n                padding: 0;\r\n                background-color: #F8F9FE;\r\n                font-family: \"Segoe UI\", Tahoma, Geneva, Verdana, sans-serif;\r\n                color: #2D3436;\r\n            }\r\n            \r\n            .email-container {\r\n                max-width: 650px;\r\n                margin: 0 auto;\r\n                background-color: #F8F9FE;\r\n                padding: 20px;\r\n            }\r\n            \r\n            /* Header */\r\n            .email-header {\r\n                background: linear-gradient(135deg, #6C5CE7 0%, #00CEC9 100%);\r\n                padding: 20px 10px;\r\n                text-align: center;\r\n                border-radius: 14px 14px 0 0;\r\n            }\r\n            \r\n            .email-header h1 {\r\n                color: #FFFFFF;\r\n                margin: 0;\r\n                font-size: 18px;\r\n                font-weight: 500;\r\n            }\r\n            \r\n            .email-header p {\r\n                color: rgba(255,255,255,0.9);\r\n                margin: 8px 0 0;\r\n                font-size: 12px;\r\n            }\r\n            \r\n            /* Job Card */\r\n            .job-card {\r\n                background: #FFFFFF;\r\n                border-radius: 14px;\r\n                margin-bottom: 20px;\r\n                overflow: hidden;\r\n                border: 1px solid #E8E8F0;\r\n                box-shadow: 0 2px 10px rgba(108, 92, 231, 0.1);\r\n                transition: all 0.3s ease;\r\n            }\r\n            \r\n            .job-card:hover {\r\n                transform: translate