-radius: 8px;\r\n                font-weight: 600;\r\n            }\r\n            \r\n            .job-date {\r\n                background: #E8F8F5;\r\n                color: #00B894;\r\n                padding: 4px 10px;\r\n                border-radius: 8px;\r\n                font-weight: 600;\r\n            }\r\n            \r\n            .job-company {\r\n                background: #FFF3E0;\r\n                color: #FDCB6E;\r\n                padding: 4px 10px;\r\n                border-radius: 8px;\r\n                font-weight: 600;\r\n            }\r\n            \r\n            .job-description {\r\n                font-size: 13px;\r\n                line-height: 1.5;\r\n                color: #636E72;\r\n                margin: 12px 0;\r\n            }\r\n            \r\n            /* Button Styles */\r\n            .btn-view {\r\n                display: inline-block;\r\n                background: linear-gradient(135deg, #6C5CE7 0%, #00CEC9 100%);\r\n                color: white;\r\n                text-decoration: none;\r\n                padding: 10px 24px;\r\n                border-radius: 25px;\r\n                font-weight: 600;\r\n                font-size: 13px;\r\n                transition: all 0.3s ease;\r\n                border: none;\r\n                cursor: pointer;\r\n                text-align: center;\r\n            }\r\n            \r\n            .btn-view:hover {\r\n                transform: translateY(-2px);\r\n                box-shadow: 0 5px 15px rgba(108, 92, 231, 0.3);\r\n            }\r\n            \r\n            /* Floating Button */\r\n            .floating-btn {\r\n                position: fixed;\r\n                bottom: 30px;\r\n                right: 30px;\r\n                background: linear-gradient(135deg, #FD79A8 0%, #FDCB6E 100%);\r\n                color: white;\r\n                padding: 14px 24px;\r\n                border-radius: 50px;\r\n                text-decoration: none;\r\n                