                  text-align: center;\r\n                }\r\n            }\r\n        </style>\r\n    </head>\r\n    <body>\r\n        <div class=\"email-container\">\r\n            \r\n            <!-- Header -->\r\n            <div class=\"email-header\">\r\n                <h1>🎯 Latest Job Opportunities</h1>\r\n                <p>Your Daily curated list of top jobs</p>\r\n            </div>\r\n            \r\n            <!-- Job Listings -->\r\n            <div style=\"padding: 20px 0;\">\r\n                <p style=\"font-size: 14px; color: #636E72; margin-bottom: 20px;\">\r\n                    Hello,<br>\r\n                    Here are the latest job opportunities matching your preferences:\r\n                </p>\r\n                <div class=\"job-card\">\r\n                    <div class=\"job-content\">\r\n                        <div class=\"job-number\">1</div>\r\n                        <h2 class=\"job-title\">\r\n                            <a href=\"https://jobadverts.ug/job/finance-associate-2/\">Finance Associate (2)</a>\r\n                        </h2>\r\n                        <div class=\"job-meta\">\r\n                            <span class=\"job-company\">🏢 The Company</span>\r\n                        </div>\r\n                        <a href=\"https://jobadverts.ug/job/finance-associate-2/\" class=\"btn-view\">\r\n                            🔍 View Details & Apply\r\n                        </a>\r\n                    </div>\r\n                </div>\r\n                <div class=\"job-card\">\r\n                    <div class=\"job-content\">\r\n                        <div class=\"job-number\">2</div>\r\n                        <h2 class=\"job-title\">\r\n                            <a href=\"https://jobadverts.ug/job/4-jobs-at-pride-bank/\">4 jobs at Pride Bank</a>\r\n                        </h2>\r\n                        <div class=\"job-meta\">\r\n                            <span class=\"job-company\">🏢 Pride Bank</span>\r\n      