(63, 1, '(20 Jobs Found Today) Latest Job Opportunities - BISure Jobs', '\r\n    <!DOCTYPE html>\r\n    <html>\r\n    <head>\r\n        <meta charset=\"UTF-8\">\r\n        <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n        <title>Latest Job Opportunities</title>\r\n        <style>\r\n            /* Global Styles */\r\n            body {\r\n                margin: 0;\r\n                padding: 0;\r\n                background-color: #F8F9FE;\r\n                font-family: \"Segoe UI\", Tahoma, Geneva, Verdana, sans-serif;\r\n                color: #2D3436;\r\n            }\r\n            \r\n            .email-container {\r\n                max-width: 650px;\r\n                margin: 0 auto;\r\n                background-color: #F8F9FE;\r\n                padding: 20px;\r\n            }\r\n            \r\n            /* Header */\r\n            .email-header {\r\n                background: linear-gradient(135deg, #6C5CE7 0%, #00CEC9 100%);\r\n                padding: 20px 10px;\r\n                text-align: center;\r\n                border-radius: 14px 14px 0 0;\r\n            }\r\n            \r\n            .email-header h1 {\r\n                color: #FFFFFF;\r\n                margin: 0;\r\n                font-size: 18px;\r\n                font-weight: 500;\r\n            }\r\n            \r\n            .email-header p {\r\n                color: rgba(255,255,255,0.9);\r\n                margin: 8px 0 0;\r\n                font-size: 12px;\r\n            }\r\n            \r\n            /* Job Card */\r\n            .job-card {\r\n                background: #FFFFFF;\r\n                border-radius: 14px;\r\n                margin-bottom: 20px;\r\n                overflow: hidden;\r\n                border: 1px solid #E8E8F0;\r\n                box-shadow: 0 2px 10px rgba(108, 92, 231, 0.1);\r\n                transition: all 0.3s ease;\r\n            }\r\n            \r\n            .job-card:hover {\r\n                transform: translateY(-2px);\r\n                box-shadow: 0 5px 20px rgba(108, 92, 231, 0.15);\r\n            }\r\n            \r\n            .job-content {\r\n                padding: 20px;\r\n            }\r\n            \r\n            .job-number {\r\n                display: inline-block;\r\n                background: linear-gradient(135deg, #6C5CE7 0%, #00CEC9 100%);\r\n                color: white;\r\n                width: 32px;\r\n                height: 32px;\r\n                border-radius: 10px;\r\n                text-align: center;\r\n                line-height: 32px;\r\n                font-weight: bold;\r\n                font-size: 16px;\r\n                margin-bottom: 12px;\r\n            }\r\n            \r\n            .job-title {\r\n                font-size: 18px;\r\n                font-weight: 700;\r\n                margin: 0 0 8px 0;\r\n                color: #2D3436;\r\n            }\r\n            \r\n            .job-title a {\r\n                color: #2D3436;\r\n                text-decoration: none;\r\n                background: linear-gradient(135deg, #6C5CE7 0%, #00CEC9 100%);\r\n                -webkit-background-clip: text;\r\n                -webkit-text-fill-color: transparent;\r\n                background-clip: text;\r\n            }\r\n            \r\n            .job-title a:hover {\r\n                background: linear-gradient(135deg, #FD79A8 0%, #FDCB6E 100%);\r\n                -webkit-background-clip: text;\r\n                -webkit-text-fill-color: transparent;\r\n                background-clip: text;\r\n            }\r\n            \r\n            .job-meta {\r\n                display: flex;\r\n                flex-wrap: wrap;\r\n                gap: 10px;\r\n                margin: 12px 0;\r\n                font-size: 12px;\r\n            }\r\n            \r\n            .job-category {\r\n                background: #F0EDFF;\r\n                color: #6C5CE7;\r\n                padding: 4px 10px;\r\n                border-radius: 8px;\r\n                font-weight: 600;\r\n            }\r\n            \r\n            .job-date {\r\n                background: #E8F8F5;\r\n                color: #00B894;\r\n                padding: 4px 10px;\r\n                border-radius: 8px;\r\n                font-weight: 600;\r\n            }\r\n            \r\n            .job-company {\r\n                background: #FFF3E0;\r\n                color: #FDCB6E;\r\n                padding: 4px 10px;\r\n                border-radius: 8px;\r\n                font-weight: 600;\r\n            }\r\n            \r\n            .job-description {\r\n                font-size: 13px;\r\n                line-height: 1.5;\r\n                color: #636E72;\r\n                margin: 12px 0;\r\n            }\r\n            \r\n            /* Button Styles */\r\n            .btn-view {\r\n                display: inline-block;\r\n                background: linear-gradient(135deg, #6C5CE7 0%, #00CEC9 100%);\r\n                color: white;\r\n                text-decoration: none;\r\n                padding: 10px 24px;\r\n                border-radius: 25px;\r\n                font-weight: 600;\r\n                font-size: 13px;\r\n                transition: all 0.3s ease;\r\n                border: none;\r\n                cursor: pointer;\r\n                text-align: center;\r\n            }\r\n            \r\n            .btn-view:hover {\r\n                transform: translateY(-2px);\r\n                box-shadow: 0 5px 15px rgba(108, 92, 231, 0.3);\r\n            }\r\n            \r\n            /* Floating Button */\r\n            .floating-btn {\r\n                position: fixed;\r\n                bottom: 30px;\r\n                right: 30px;\r\n                background: linear-gradient(135deg, #FD79A8 0%, #FDCB6E 100%);\r\n                color: white;\r\n                padding: 14px 24px;\r\n                border-radius: 50px;\r\n                text-decoration: non