 transform: translateY(-2px);\r\n                box-shadow: 0 5px 20px rgba(108, 92, 231, 0.15);\r\n            }\r\n            \r\n            .job-content {\r\n                padding: 20px;\r\n            }\r\n            \r\n            .job-number {\r\n                display: inline-block;\r\n                background: linear-gradient(135deg, #6C5CE7 0%, #00CEC9 100%);\r\n                color: white;\r\n                width: 32px;\r\n                height: 32px;\r\n                border-radius: 10px;\r\n                text-align: center;\r\n                line-height: 32px;\r\n                font-weight: bold;\r\n                font-size: 16px;\r\n                margin-bottom: 12px;\r\n            }\r\n            \r\n            .job-title {\r\n                font-size: 18px;\r\n                font-weight: 700;\r\n                margin: 0 0 8px 0;\r\n                color: #2D3436;\r\n            }\r\n            \r\n            .job-title a {\r\n                color: #2D3436;\r\n                text-decoration: none;\r\n                background: linear-gradient(135deg, #6C5CE7 0%, #00CEC9 100%);\r\n                -webkit-background-clip: text;\r\n                -webkit-text-fill-color: transparent;\r\n                background-clip: text;\r\n            }\r\n            \r\n            .job-title a:hover {\r\n                background: linear-gradient(135deg, #FD79A8 0%, #FDCB6E 100%);\r\n                -webkit-background-clip: text;\r\n                -webkit-text-fill-color: transparent;\r\n                background-clip: text;\r\n            }\r\n            \r\n            .job-meta {\r\n                display: flex;\r\n                flex-wrap: wrap;\r\n                gap: 10px;\r\n                margin: 12px 0;\r\n                font-size: 12px;\r\n            }\r\n            \r\n            .job-category {\r\n                background: #F0EDFF;\r\n                color: #6C5CE7;\r\n                padding: 4px 10px;\r\n                border-radius: 8px;\r\n                font-weight: 600;\r\n            }\r\n            \r\n            .job-date {\r\n                background: #E8F8F5;\r\n                color: #00B894;\r\n                padding: 4px 10px;\r\n                border-radius: 8px;\r\n                font-weight: 600;\r\n            }\r\n            \r\n            .job-company {\r\n                background: #FFF3E0;\r\n                color: #FDCB6E;\r\n                padding: 4px 10px;\r\n                border-radius: 8px;\r\n                font-weight: 600;\r\n            }\r\n            \r\n            .job-description {\r\n                font-size: 13px;\r\n                line-height: 1.5;\r\n                color: #636E72;\r\n                margin: 12px 0;\r\n            }\r\n            \r\n            /* Button Styles */\r\n            .btn-view {\r\n                display: inline-block;\r\n                background: linear-gradient(135deg, #6C5CE7 0%, #00CEC9 100%);\r\n                color: white;\r\n                text-decoration: none;\r\n                padding: 10px 24px;\r\n                border-radius: 25px;\r\n                font-weight: 600;\r\n                font-size: 13px;\r\n                transition: all 0.3s ease;\r\n                border: none;\r\n                cursor: pointer;\r\n                text-align: center;\r\n            }\r\n            \r\n            .btn-view:hover {\r\n                transform: translateY(-2px);\r\n                box-shadow: 0 5px 15px rgba(108, 92, 231, 0.3);\r\n            }\r\n            \r\n            /* Floating Button */\r\n            .floating-btn {\r\n                position: fixed;\r\n                bottom: 30px;\r\n                right: 30px;\r\n                background: linear-gradient(135deg, #FD79A8 0%, #FDCB6E 100%);\r\n                color: white;\r\n                padding: 14px 24px;\r\n                border-radius: 50px;\r\n                text-decoration: none;\r\n                font-weight: 700;\r\n                font-size: 14px;\r\n                box-shadow: 0 5px 20px rgba(253, 121, 168, 0.4);\r\n                transition: all 0.3s ease;\r\n                display: inline-flex;\r\n                align-items: center;\r\n                gap: 8px;\r\n                z-index: 1000;\r\n            }\r\n            \r\n            .floating-btn:hover {\r\n                transform: translateY(-3px);\r\n                box-shadow: 0 8px 25px rgba(253, 121, 168, 0.5);\r\n            }\r\n            \r\n            /* Footer */\r\n            .email-footer {\r\n                background: #2D3436;\r\n                padding: 20px;\r\n                text-align: center;\r\n                border-radius: 0 0 14px 14px;\r\n                margin-top: 20px;\r\n            }\r\n            \r\n            .email-footer p {\r\n                color: #B2BEC3;\r\n                font-size: 11px;\r\n                margin: 5px 0;\r\n            }\r\n            \r\n            .email-footer a {\r\n                color: #6C5CE7;\r\n                text-decoration: none;\r\n            }\r\n            \r\n            hr {\r\n                border: none;\r\n                height: 2px;\r\n                background: linear-gradient(135deg, #6C5CE7 0%, #00CEC9 100%);\r\n                margin: 20px 0;\r\n            }\r\n            \r\n            @media only screen and (max-width: 600px) {\r\n                .email-container {\r\n                    padding: 10px;\r\n                }\r\n                .job-content {\r\n                    padding: 15px;\r\n                }\r\n                .job-title {\r\n                    font-size: 16px;\r\n                }\r\n                .floating-btn {\r\n                    bottom: 20px;\r\n                    right: 20px;\r\n                    padding: 10px 18px;\r\n                    font-size: 12px;\r\n                }\r\n                .btn-view {\r\n                    display: block;\r\n                    text-align: center;\r\n                }\r\n            }\r\n        </style>\r\n    </head>\r\n    <body>\r\n        <div class=\"email-container\">\r\n            \r\n            <!-- Header -->\r\n            <div class=\"email-header\">\r\n                <h1>🎯 Latest Job Opportunities</h1>\r\n                <p>Your Daily curated list of top jobs (7 new opportunities)</p>\r\n            </div>\r\n            \r\n            <!-- Job Listings -->\r\n            <div style=\"padding: 20px 0;\">\r\n                <p style=\"font-size: 14px; color: #636E72; margin-bottom: 20px;\">\r\n                    Hello,<br>\r\n                    Here are the latest job opportunities matching your preferences:\r\n                </p>\r\n                <div class=\"job-card\">\r\n                    <div class=\"job-content\">\r\n                        <div class=\"job-number\">1</div>\r\n                        <h2 class=\"job-title\">\r\n                            <a href=\"https://jobadverts.ug/job/primary-teachers-for-deaf-learners-10-positions/\">Primary Teachers for Deaf Learners (10 Positions)</a>\r\n                        </h2>\r\n                        <div class=\"job-meta\">\r\n                            <span class=\"job-company\">🏢 The Company</span>\r\n                        </div>\r\n                        <a href=\"https://jobadverts.ug/job/primary-teachers-for-deaf-learners-10-positions/\" class=\"btn-view\">\r\n                            🔍 View Details & Apply\r\n                        </a>\r\n                    </div>\r\n                </div>\r\n                <div class=\"job-card\">\r\n                    <div class=\"job-content\">\r\n                        <div class=\"job-number\">2</div>\r\n                        <h2 class=\"job-title\">\r\n                            <a href=\"https://jobadverts.ug/job/underwriting-officer-fire-engineering-department/\">Underwriting Officer – Fire &amp; Engineeri